//! Bedy Proof of Concept declarations crate

mod objects {
    pub mod normalized {
        use bedy_common::Id;

        pub struct Person {
            pub name: String,
            pub city: Id<City>,
        }

        pub struct City {
            // #[bedy(unique)]
            pub name: String,
        }

        // TODO: autogenerated because of #[bedy(unique)]
        #[cfg(feature = "server")]
        mod city_indexes {
            use bedy_server::index::Index;

            impl Index<super::City> for String {}
        }
    }

    pub mod denormalized {
        pub struct PersonDisplay {
            pub name: String,
            pub city: String,
        }
    }
}

mod queries {
    // TODO: generate these automatically?
    mod auto {
        mod person {
            use bedy_common::{Id, Record};
            use bedy_server::{
                extractor::Param,
                query::{Query, QueryMut},
            };

            use crate::objects::normalized::Person;

            fn insert(Param(person): Param<Person>, mut people: QueryMut<Person>) -> Id<Person> {
                people.insert(&person)
            }

            fn find(Param(id): Param<Id<Person>>, people: Query<Person>) -> Option<Person> {
                people.find(id).map(|(_, object)| object)
            }

            fn update(Param(record): Param<Record<Person>>, mut people: QueryMut<Person>) {
                people.update(record);
            }

            fn remove(Param(id): Param<Id<Person>>, mut people: QueryMut<Person>) {
                people.delete(id);
            }
        }

        mod city {
            use bedy_common::Record;
            use bedy_server::{extractor::Param, query::Query};

            use crate::objects::normalized::City;

            fn find_by_name(Param(name): Param<String>, cities: Query<City, String>) -> Option<Record<City>> {
                cities.find(name)
            }
        }
    }

    mod custom {
        mod people {
            use bedy_common::Id;
            use bedy_server::{extractor::Param, query::Query};

            use crate::objects::{
                denormalized::PersonDisplay,
                normalized::{City, Person},
            };

            fn display_people(people: Query<Person>, cities: Query<City>) -> impl Iterator<Item = PersonDisplay> {
                people.iter().map(move |(_id, person)| PersonDisplay {
                    name: person.name,
                    city: cities.find(person.city).expect("foreign key exists").1.name,
                })
            }

            fn people_within(Param(city): Param<Id<City>>, people: Query<Person>) -> impl Iterator<Item = Id<Person>> {
                people.iter().filter_map(move |(id, person)| (person.city == city).then_some(id))
            }
        }
    }
}

