mod chained_sketch {
    use bedy_client::ClientCrud;
    use futures::StreamExt;

    use crate::client::*;

    // Back and forth
    async fn remove_people_in(city_name: &str, db: &BedyClient) -> usize {
        let mut removed_count = 0;

        if let Some((city_id, _)) = db.city().find_by_name(city_name).await {
            while let Some(person_id) = db.person().people_within(city_id).await.next().await {
                if db.person().remove(person_id).await.is_some() {
                    removed_count += 1;
                }
            }
        }

        removed_count
    }

    // TODO: pipelined, only city_name and count are transferred over the wire
    async fn pipelined_remove_people_in(city_name: &str, db: &BedyClient) -> usize {}
}
